//! Declarative tool manifest â€” the single source of truth for the agent CLI's
//! command surface. Generated by the MCP pipeline (`services/mcp/scripts/generate-cli-manifest.ts`)
//! and embedded at build time, so the CLI stays in lockstep with the MCP.

use anyhow::{Context, Result};
use serde::Deserialize;
use serde_json::{Map, Value};
use std::collections::BTreeMap;

// Single source of truth: the manifest the MCP pipeline emits. A standalone build
// outside the monorepo would vendor this in via a build step instead.
const MANIFEST_JSON: &str = include_str!("../../../services/mcp/schema/cli-manifest.json");

#[derive(Debug, Deserialize)]
pub struct Manifest {
    #[serde(default)]
    pub version: u32,
    pub tools: BTreeMap<String, Tool>,
}

#[derive(Debug, Deserialize)]
pub struct Tool {
    pub mcp_name: String,
    pub category: String,
    pub verb: String,
    pub method: String,
    pub path: String,
    #[serde(default)]
    pub scopes: Vec<String>,
    #[serde(default)]
    pub annotations: Annotations,
    #[serde(default)]
    pub params: Params,
    /// `true` â†’ soft-delete via PATCH `{ "deleted": true }`; a string â†’ PATCH `{ "<field>": true }`.
    #[serde(default)]
    pub soft_delete: Option<SoftDelete>,
    /// Static key/values always merged into the request body.
    #[serde(default)]
    pub inject_body: Map<String, Value>,
    /// Present for query-wrapper tools (POST to the query endpoint).
    #[serde(default)]
    pub query_wrapper: Option<QueryWrapper>,
    /// State key to resolve a param from when the caller omits it (`projectId` | `orgId`).
    #[serde(default)]
    pub fallbacks: BTreeMap<String, String>,
    /// Response-shaping hint (not part of the request; carried for the UX layer).
    #[serde(default)]
    pub enrich_url: Option<String>,
    #[serde(default)]
    pub response_include: Option<Vec<String>>,
}

impl Tool {
    /// The body field to set to `true` for a soft-delete, or `None` if not a soft-delete tool.
    pub fn soft_delete_field(&self) -> Option<String> {
        match &self.soft_delete {
            Some(SoftDelete::Field(f)) => Some(f.clone()),
            Some(SoftDelete::Flag(true)) => Some("deleted".to_string()),
            _ => None,
        }
    }
}

#[derive(Debug, Default, Deserialize)]
pub struct Annotations {
    #[serde(default)]
    pub read_only: bool,
    #[serde(default)]
    pub destructive: bool,
    #[serde(default)]
    pub idempotent: bool,
}

#[derive(Debug, Default, Deserialize)]
pub struct Params {
    #[serde(default)]
    pub path: Vec<Param>,
    #[serde(default)]
    pub query: Vec<Param>,
    #[serde(default)]
    pub body: Vec<Param>,
}

#[derive(Debug, Deserialize)]
pub struct Param {
    pub name: String,
    #[serde(rename = "type", default)]
    pub ty: String,
    #[serde(default)]
    pub required: bool,
    #[serde(default)]
    pub flag_eligible: bool,
    /// e.g. `"string-int"` â€” applied client-side before the value hits the wire.
    #[serde(default)]
    pub cast: Option<String>,
    /// Send under this wire name instead of `name` (mirrors MCP `rename_params`).
    #[serde(default)]
    pub rename: Option<String>,
    /// Default applied when the caller omits the field (mirrors the MCP schema's zod `.default()`).
    #[serde(default)]
    pub default: Option<Value>,
    #[serde(default)]
    pub description: Option<String>,
}

#[derive(Debug, Deserialize)]
#[serde(untagged)]
pub enum SoftDelete {
    Flag(bool),
    Field(String),
}

#[derive(Debug, Deserialize)]
pub struct QueryWrapper {
    /// The `kind` injected into the query body (e.g. `TrendsQuery`, `InsightActorsQuery`).
    pub kind: String,
    /// Present for `*-actors` tools that re-wrap into a generic `ActorsQuery`.
    #[serde(default)]
    pub actors: Option<ActorsConfig>,
}

#[derive(Debug, Deserialize)]
pub struct ActorsConfig {
    /// Variant selected by the runtime `query.source.kind` (mirrors `client.ts` `runActorsQuery`).
    pub source_kind_map: BTreeMap<String, ActorsVariant>,
    /// Input field whose truthiness appends `recordings_select` to the actors `select`.
    #[serde(default)]
    pub include_recordings_field: Option<String>,
    #[serde(default)]
    pub recordings_select: Option<String>,
}

#[derive(Debug, Deserialize)]
pub struct ActorsVariant {
    pub select: Vec<String>,
    pub order_by: Vec<String>,
    pub limit: i64,
}

pub fn load_manifest() -> Result<Manifest> {
    serde_json::from_str(MANIFEST_JSON).context("Failed to parse embedded cli-manifest.json")
}
